import sailpoint.object.Application;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("Ascension.Rule.IdentitySelector.ServiceNow");

  logger.debug("Entering Ascension-Rule-IdentitySelector-ServiceNow");
  boolean flag = false;
  boolean adLink = false;
  boolean authLink = false;
  boolean snowLink = false;
   String ministryValue = "";
  
  if(identity!=null){
	ministryValue = identity.getStringAttribute("ministry");
	if(Util.nullSafeCaseInsensitiveEq(ministryValue,"AMITA Health") ){
		
	  identity = context.getObjectByName(Identity.class, identity.getName());
	  List links = identity.getLinks();
	  if(!Util.isEmpty(links) && !identity.isInactive()){
		for(Link link : links){
		  if(link !=null && !link.isDisabled() && link.getApplication() !=null){
			if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getType(),"Active Directory - Direct") &&  Util.nullSafeCaseInsensitiveEq(link.getApplicationName(),"AD-AMITA")){
			  adLink = true;
			 
			}
			if(link.getApplication().isAuthoritative()){
			  authLink = true;
			}
			if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getType(),"ServiceNow")){
			  snowLink = true;
			  break;
			}
			if(adLink){
			  flag = true;
			  break;
			}
		  }
		}
	  }
	}
  }
  if(snowLink){
    flag = false;
  }
  logger.debug("Existing Ascension-Rule-IdentitySelector-ServiceNow");
  return flag;
